          {method === 'netbanking' && (
            <div className="gw-form">
              <div className="gw-bank-list">
                {BANKS.map(b => (
                  <button key={b.id} className={`gw-bank-btn ${bank===b.id?'active':''}`} onClick={() => setBank(b.id)}>{b.name}</button>
                ))}
