                  {c.status?.replace('_',' ')}
                </div>
              </div>
            </div>
          ))}
          <button className="btn-ghost" onClick={() => nav('claims')} style={{ marginTop:10 }}>
            View all claims <Icon name="arrow" size={13}/>
          </button>
        </div>
      )}
    </div>
  );
}

